// Código para nó Code no n8n
// Extrai legenda do X gerada pela IA

const items = $input.all();
const legendas = [];

for (const item of items) {
  try {
    // Tenta acessar o output da IA
    let rawOutput = item.json.output || item.json.text || item.json;

    // Se for string, faz o parse
    if (typeof rawOutput === 'string') {
      // Remove markdown e prefixos
      rawOutput = rawOutput
        .replace(/```json\n?/g, '')
        .replace(/```\n?/g, '')
        .trim();

      // Parse do JSON
      const parsed = JSON.parse(rawOutput);
      legendas.push(parsed);
    } 
    // Se já for objeto
    else if (typeof rawOutput === 'object' && !Array.isArray(rawOutput)) {
      legendas.push(rawOutput);
    }

  } catch (error) {
    console.error('Erro ao processar legenda:', error.message);
    console.error('Raw output:', item.json.output || item.json.text || item.json);
  }
}

// Valida se temos legendas
if (legendas.length === 0) {
  throw new Error('Nenhuma legenda foi extraída. Verifique o formato da resposta da IA.');
}

// Retorna cada legenda como um item separado
return legendas.map((legenda) => {
  // Validação básica
  if (!legenda.legenda_x) {
    console.warn('Legenda sem conteúdo, pulando...');
    return null;
  }

  return {
    json: {
      legenda_x: legenda.legenda_x
    }
  };
}).filter(item => item !== null); // Remove items inválidos
